  bool can_use_miopen_channels_last_3d = suggest_nhwc && (weight_ndim == 5) && (\
    (input_memory_format  == at::MemoryFormat::ChannelsLast3d) ||\
    (weight_memory_format == at::MemoryFormat::ChannelsLast3d)\
