561: std::tuple<Tensor, Tensor, Tensor, Tensor, int64_t> _batch_norm_impl_index(
562:     const Tensor& input, const std::optional<Tensor>& weight_opt /* optional */, const std::optional<Tensor>& bias_opt /* optional */, const std::optional<Tensor>& running_mean_opt /* optional */, const std::optional<Tensor>& running_var_opt /* optional */,
563:     bool training, double momentum, double eps, bool cudnn_enabled) {
564:   // See [Note: hacky wrapper removal for optional tensor]
565:   c10::MaybeOwned<Tensor> weight_maybe_owned = at::borrow_from_optional_tensor(weight_opt);
566:   const Tensor& weight = *weight_maybe_owned;
567:   const Tensor& bias = bias_opt.value_or(Tensor());
568:   const Tensor& running_mean = running_mean_opt.value_or(Tensor());
569:   const Tensor& running_var = running_var_opt.value_or(Tensor());
570: 
571:   auto num_features = input.sym_sizes()[1];
572: 
573:   if (input.sym_numel() == 0) {
574:     Tensor reserve = at::empty({0}, input.options().dtype(kByte));
575:     auto options = input.options().dtype(
576:         at::toAccumulateType(input.scalar_type(), input.device().type()));
577:     auto save_mean = at::empty_symint(c10::SymIntArrayRef({num_features}), options);
578:     auto save_invstd = at::empty_symint(c10::SymIntArrayRef({std::move(num_features)}), options);
579: 
580:     // don't return view of input, don't return empty tensor because it will break gradient chain
581:     auto out = input.clone();
582:     if (weight.defined()) out = out * weight[0];
583:     if (bias.defined()) out = out + bias[0];
584:     return std::tuple<Tensor, Tensor, Tensor, Tensor, int64_t>(
585:         out, save_mean, save_invstd, reserve, 0);
586:   }
587: 
588:   if (running_mean.defined()) {
589:     check_dims_match_num_input_features("running_mean", num_features, running_mean.sym_numel());
590:   } else if (!training) {
591:     TORCH_CHECK(false, "running_mean must be defined in evaluation mode");
592:   }
593:   if (running_var.defined()) {
594:     check_dims_match_num_input_features("running_var", num_features, running_var.sym_numel());
595:   } else if (!training) {
596:     TORCH_CHECK(false, "running_var must be defined in evaluation mode");
597:   }
598:   if (weight.defined()) {
599:     check_dims_match_num_input_features("weight", num_features, weight.sym_numel());
600:   }
601:   if (bias.defined()) {
602:     check_dims_match_num_input_features("bias", std::move(num_features), bias.sym_numel());
