725: Tensor instance_norm(
726:     const Tensor& input, const std::optional<Tensor>& weight_opt /* optional */, const std::optional<Tensor>& bias_opt /* optional */, const std::optional<Tensor>& running_mean_opt /* optional */, const std::optional<Tensor>& running_var_opt /* optional */,
727:     bool use_input_stats, double momentum, double eps, bool cudnn_enabled) {
728:   // See [Note: hacky wrapper removal for optional tensor]
729:   c10::MaybeOwned<Tensor> weight_maybe_owned = at::borrow_from_optional_tensor(weight_opt);
730:   const Tensor& weight = *weight_maybe_owned;
731:   const Tensor& bias = bias_opt.value_or(Tensor());
732:   const Tensor& running_mean = running_mean_opt.value_or(Tensor());
733:   const Tensor& running_var = running_var_opt.value_or(Tensor());
734: 
735:  TORCH_CHECK(use_input_stats || (running_mean.defined() && running_var.defined()),
736:            "Expected running_mean and running_var to be defined when use_input_stats is false");
737:   std::vector<SymInt> shape = input.sym_sizes().vec();
738:   SymInt b = input.sym_size(0);
739:   SymInt c = input.sym_size(1);
740:   shape[1] = b * c;
741:   shape[0] = SymInt(1);
742: 
743:   Tensor weight_ = repeat_if_defined(weight, b);
744:   Tensor bias_ = repeat_if_defined(bias, b);
745:   Tensor running_mean_ = repeat_if_defined(running_mean, b);
746:   Tensor running_var_ = repeat_if_defined(running_var, b);
747: 
748:   auto input_reshaped = input.contiguous().view_symint(shape);
749:   auto out = at::batch_norm(input_reshaped, weight_, bias_, running_mean_, running_var_,
750:                             use_input_stats, momentum, eps, cudnn_enabled);
751: 
752:   // we alias running_mean and running_var because they are const but we want to modify their data
753:   if (running_mean.defined()) {
754:     at::alias(running_mean).copy_(running_mean_.view_symint({ b, c }).mean(0, false));
755:   }
756:   if (running_var.defined()) {
757:     at::alias(running_var).copy_(running_var_.view_symint({ std::move(b), std::move(c) }).mean(0, false));
758:   }
759: 
760:   return out.view_symint(input.sym_sizes());
761: }
