830: std::tuple<Tensor, Tensor, Tensor> batch_norm_cpu(const Tensor& self, const std::optional<Tensor>& weight_opt, const std::optional<Tensor>& bias_opt, const std::optional<Tensor>& running_mean_opt, const std::optional<Tensor>& running_var_opt,
831:                                                   bool train, double momentum, double eps) {
832:   // See [Note: hacky wrapper removal for optional tensor]
833:   c10::MaybeOwned<Tensor> weight_maybe_owned = at::borrow_from_optional_tensor(weight_opt);
834:   const Tensor& weight = *weight_maybe_owned;
835:   const Tensor& bias = bias_opt.value_or(Tensor());
836:   const Tensor& running_mean = running_mean_opt.value_or(Tensor());
837:   const Tensor& running_var = running_var_opt.value_or(Tensor());
838: 
839:   checkBackend("batch_norm_cpu", {self, weight, bias, running_mean, running_var}, Backend::CPU);
840: 
841:   // Prepare output tensor
842:   const bool all_contiguous = is_contiguous(self)
843:     && (!weight.defined() || weight.is_contiguous())
844:     && (!bias.defined() || bias.is_contiguous())
845:     && running_mean.is_contiguous()
846:     && running_var.is_contiguous();
847:   Tensor output = at::empty_like(self, all_contiguous ? suggest_memory_format_contig(self) : self.suggest_memory_format());
848: 
849:   // Prepare save_mean and save_var
850:   Tensor save_var;
851:   Tensor save_mean;
852:   const bool mixed_type = is_mixed_type(self, weight, bias, running_mean, running_var);
853:   const int64_t ndim = self.dim();
854:   DimVector reduce_dims(ndim - 1);
855:   reduce_dims[0] = 0;
856:   for (const auto i : c10::irange(2, ndim)) {
857:     reduce_dims[i - 1] = i;
858:   }
859:   if (mixed_type) {
860:     if (!train) {
861:       save_mean = at::empty({0}, self.options().dtype(kFloat));
862:       save_var = at::empty({0}, self.options().dtype(kFloat));
863:     } else {
864:       save_mean = is_contiguous(self) ? at::empty({self.size(1)}, self.options().dtype(kFloat)) : at::mean(self, /*dim=*/reduce_dims, /*keepdim=*/false, kFloat);
865:       save_var = at::empty({self.size(1)}, self.options().dtype(kFloat));
866:     }
867:   } else {
868:     if (!train) {
869:       save_mean = at::empty({0}, self.options());
870:       save_var = at::empty({0}, self.options());
871:     } else {
872:       save_mean = is_contiguous(self) ? at::empty({self.size(1)}, self.options()) : at::mean(self, /*dim=*/reduce_dims, /*keepdim=*/false);
873:       save_var = at::empty({self.size(1)}, self.options());
874:     }
875:   }
876:   return batch_norm_cpu_out(self, weight_opt, bias_opt, running_mean_opt, running_var_opt, train, momentum, eps, output, save_mean, save_var);
877: }
