967: TORCH_IMPL_FUNC(renorm_out)(const Tensor& self, const Scalar& p, int64_t dim,
968:                             const Scalar& maxnorm, const Tensor& out) {
969:   auto self_sizes = self.sizes();
970:   dim = c10::maybe_wrap_dim(dim, self_sizes.size());
971: 
972:   DimVector reduce_dims(self_sizes.size());
973:   std::iota(reduce_dims.begin(), reduce_dims.end(), 0);
974:   reduce_dims.erase(reduce_dims.begin() + dim);
975: 
976:   // For cuda half, calculate norm in float precision then cast
977:   // normalization factor to half
978:   auto dtype = self.scalar_type();
979:   auto acc_type = at::toAccumulateType(dtype, /*is_cuda=*/true);
980:   Tensor norm;
981:   if (acc_type != dtype) {
982:     norm = at::linalg_vector_norm(self, p.toDouble(), reduce_dims,
983:                                   /*keepdim=*/true, /*dtype=*/acc_type);
984:   } else {
985:     norm = at::linalg_vector_norm(self, p.toDouble(), reduce_dims,
986:                                   /*keepdim=*/true);
987:   }
988: 
989:   auto factor = (acc_type == c10::toRealValueType(dtype)) ?
990:       norm : at::empty(norm.sizes(), self.options());
991:   auto iter = TensorIteratorConfig()
992:       .add_output(factor)
993:       .add_input(norm)
994:       .set_check_mem_overlap(false)
995:       .cast_common_dtype_to_outputs(true)
996:       .build();
997: 
998:   renorm_scale_factor_stub(iter.device_type(), iter, maxnorm.toDouble());
999:   at::mul_outf(self, factor, const_cast<Tensor&>(out));
1000: }
